const synthesis = $input.first().json;

// Optional: fallback values
const topic = synthesis.research_topic || 'Research Topic';
const timestamp = new Date().toLocaleString();

const md = `# Research Brief: ${topic}

**Generated:** ${timestamp}  
**Confidence Level:** ${synthesis.synthesis_confidence ?? 'N/A'}%

---

## ✅ What We Know

${synthesis.executive_summary || 'No executive summary provided.'}

### Key Insights
${(synthesis.key_insights || []).map((k, i) => 
  `${i + 1}. **${k.insight}** (${k.confidence}% confidence)
   - Why it matters: ${k.implications}`
).join('\n\n') || 'No key insights available.'}

---

## ⚠️ What We're Unsure About

### Conflicting Views
${(synthesis.conflicting_views && synthesis.conflicting_views.length > 0)
  ? synthesis.conflicting_views.map((cv, i) =>
`**Conflict ${i + 1}:**
- Perspective A: ${cv.view_a}
- Perspective B: ${cv.view_b}
- Resolution: ${cv.resolution}`
).join('\n\n')
  : 'No major conflicts detected.'}

### Open Questions
${(synthesis.open_questions || []).map((q, i) =>
`${i + 1}. **${q.question}**
- Why it matters: ${q.why_it_matters}
- Data needed: ${q.data_needed}`
).join('\n\n') || 'No open questions identified.'}

---

## ➡️ What to Do Next

${(synthesis.recommended_next_actions || []).map((a, i) =>
`${i + 1}. **${a.action}**
- Rationale: ${a.rationale}
${a.timeline ? `- Timeline: ${a.timeline}` : ''}`
).join('\n\n') || 'No next actions defined.'}

---

## 🔍 Methodology

- **Analysis confidence:** ${synthesis.synthesis_confidence ?? 'N/A'}%
- **Reasoning:** ${synthesis.confidence_rationale || 'No rationale provided.'}

---

**Next research run recommended in:** 7–14 days
`;

return [
  {
    json: {
      markdown_brief: md,
      generated_at: new Date().toISOString()
    }
  }
];

